def solve(arg1: dict) -> dict:
    member_id = arg1.get('member_id')
    challenge_id = arg1.get('challenge_id')
    submitted = arg1.get('submitted', False)

    # Simulate challenge state and submissions for testing
    challenge_state = {
        'is_closed': False,  # Assume challenge is open
        'valid_members': ['12345'],  # Assume member '12345' is valid
        'submissions': {
            '67890': ['submission1', 'submission2', 'submission3']  # Example submissions
        }
    }

    can_download = False
    downloadable_submissions = []

    # Check if the member is valid
    if member_id not in challenge_state['valid_members']:
        return {'can_download': False}

    # Check if the challenge is closed
    if challenge_state['is_closed']:
        return {'can_download': False}

    # Check if the submission is valid
    if submitted:
        can_download = True
        downloadable_submissions = challenge_state['submissions'].get(challenge_id, [])

    return {
        'can_download': can_download,
        'downloadable_submissions': downloadable_submissions
    }
